update.if:
UPDATE  TB_GNRL_MBER
   SET  MBER_NM          = #{userNm}
      , MBER_EMAIL_ADRES = #{email}
      , MBTLNUM          = #{telno}
      , ZIP              = #{zip}
      , ADRES            = #{adres}
      , DETAIL_ADRES     = #{detailAdres}
      , LAST_UPDT_PNTTM  = sysdate()
      , LAST_UPDUSR_ID   = #{userId}
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_EMPLYR_INFO
   SET  USER_NM         = #{userNm}
      , EMAIL_ADRES     = #{email}
      , MBTLNUM         = #{telno}
      , ZIP             = #{zip}
      , HOUSE_ADRES     = #{adres}
      , DETAIL_ADRES    = #{detailAdres}
      , LAST_UPDT_PNTTM = sysdate()
      , LAST_UPDUSR_ID  = #{userId}
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_ENTRPRS_MBER
   SET  CMPNY_NM            = #{userNm}
      , APPLCNT_EMAIL_ADRES = #{email}
      , TELNO               = #{telno}
      , ZIP                 = #{zip}
      , ADRES               = #{adres}
      , DETAIL_ADRES        = #{detailAdres}
      , LAST_UPDT_PNTTM     = sysdate()
      , LAST_UPDUSR_ID      = #{userId}
 WHERE  ESNTL_ID = #{uniqId}

select.if:
SELECT  PASSWORD AS password
  FROM  TB_GNRL_MBER
 WHERE  ESNTL_ID = #{uniqId}

SELECT  PASSWORD AS password
  FROM  TB_EMPLYR_INFO
 WHERE  ESNTL_ID = #{uniqId}

SELECT  ENTRPRS_MBER_PASSWORD AS password
  FROM  TB_ENTRPRS_MBER
 WHERE  ESNTL_ID = #{uniqId}

update.if:
UPDATE  TB_GNRL_MBER
   SET  PASSWORD = #{password}
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_EMPLYR_INFO
   SET  PASSWORD = #{password}
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_ENTRPRS_MBER
   SET  ENTRPRS_MBER_PASSWORD = #{password}
 WHERE  ESNTL_ID = #{uniqId}
